class ErrorHandler:
    @staticmethod
    def create_error_details(exception, context_info, service_state):
        error_details = {
            'error_type': type(exception).__name__,
            'error_message': str(exception),
            'stack_trace': traceback.format_exc(),
            'timestamp': datetime.now().isoformat(),
            'context': context_info,
            'service_state': service_state,
            'python_version': sys.version,
            'exception_args': list(exception.args) if hasattr(exception, 'args') else []
        }
        return json.dumps(error_details, indent=2, default=str)
    
    @staticmethod
    def handle_exception(exception, context, method_name, request_id, service_state):
        context_info = {
            'method': method_name,
            'request_id': request_id,
            'peer': context.peer() if context else 'unknown',
            'time_remaining': context.time_remaining() if context and hasattr(context, 'time_remaining') else None
        }
        
        state_snapshot = service_state.get_state()
        error_details = ErrorHandler.create_error_details(exception, context_info, state_snapshot)
        
        service_state.record_error({
            'method': method_name,
            'error_type': type(exception).__name__,
            'message': str(exception),
            'timestamp': datetime.now().isoformat()
        })
        
        if isinstance(exception, ValueError):
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details(f"Invalid argument error in {method_name}:\n{error_details}")
        elif isinstance(exception, PermissionError):
            context.set_code(grpc.StatusCode.PERMISSION_DENIED)
            context.set_details(f"Permission denied in {method_name}:\n{error_details}")
        elif isinstance(exception, FileNotFoundError):
            context.set_code(grpc.StatusCode.NOT_FOUND)
            context.set_details(f"Resource not found in {method_name}:\n{error_details}")
        elif isinstance(exception, TimeoutError):
            context.set_code(grpc.StatusCode.DEADLINE_EXCEEDED)
            context.set_details(f"Timeout in {method_name}:\n{error_details}")
        elif isinstance(exception, NotImplementedError):
            context.set_code(grpc.StatusCode.UNIMPLEMENTED)
            context.set_details(f"Not implemented in {method_name}:\n{error_details}")
        elif isinstance(exception, ConnectionError):
            context.set_code(grpc.StatusCode.UNAVAILABLE)
            context.set_details(f"Service unavailable in {method_name}:\n{error_details}")
        else:
            context.set_code(grpc.StatusCode.INTERNAL)
            context.set_details(f"Internal error in {method_name}:\n{error_details}")
        
        return None


